/// <summary>
/// Color import
/// </summary>
public class ETG_Acu_EcoResColorImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_EcoResColorImport  colorImport;

    colorImport = ETG_Acu_EcoResColorImport::construct();

    if (colorImport.prompt())
    {
        colorImport.runOperation();
    }
}

public static ETG_Acu_EcoResColorImport construct()
{
    return new ETG_Acu_EcoResColorImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    EcoResProductColorEntity    color;
    EcoResColorName             colorName;

    colorName = conpeek(_con, 1);

    select firstonly color
        where color.ColorId == colorName;

    if (!color)
    {
        color.ColorId   = conpeek(_con, 1);
        color.insert();
    }
}

/// <summary>
/// Import colors
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpColor";

    return ret;
}
